# main.tf — multicloud provider configuration
terraform {
  required_providers {
    azurerm = { source = "hashicorp/azurerm", version = "~> 3.0" }
    aws     = { source = "hashicorp/aws",     version = "~> 5.0" }
    google  = { source = "hashicorp/google",  version = "~> 5.0" }
  }
}

provider "azurerm" {
  features {}
  # uses AZURE_CLIENT_ID / AZURE_CLIENT_SECRET / AZURE_TENANT_ID env vars
}
provider "aws" {
  region = "us-east-1"
  # uses AWS_ACCESS_KEY_ID / AWS_SECRET_ACCESS_KEY env vars
}
provider "google" {
  project = "my-gcp-project"
  region  = "asia-east1"
  # uses GOOGLE_APPLICATION_CREDENTIALS env var
}

# Azure: primary VNet
resource "azurerm_virtual_network" "main" {
  name                = "prod-vnet"
  resource_group_name = azurerm_resource_group.main.name
  location            = "eastus"
  address_space       = ["10.0.0.0/16"]
}

# AWS: secondary VPC
resource "aws_vpc" "main" {
  cidr_block = "10.1.0.0/16"
  tags       = { Name = "prod-vpc" }
}

# GCP: tertiary VPC
resource "google_compute_network" "main" {
  name                    = "prod-vpc"
  auto_create_subnetworks = false
}

# Azure Data Factory pipeline: copy from S3 to Azure Data Lake
# (Azure Portal or ARM template — shown as az CLI for brevity)
az datafactory pipeline create \
  --resource-group data-rg \
  --factory-name corp-adf \
  --name s3-to-adls \
  --pipeline '{
    "activities": [{
      "type": "Copy",
      "name": "CopyFromS3",
      "inputs": [{"referenceName": "S3Dataset", "type": "DatasetReference"}],
      "outputs": [{"referenceName": "ADLSGen2Dataset", "type": "DatasetReference"}],
      "typeProperties": {
        "source": {"type": "BinarySource", "storeSettings": {"type": "AmazonS3ReadSettings"}},
        "sink": {"type": "BinarySink", "storeSettings": {"type": "AzureBlobFSWriteSettings"}}
      }
    }]
  }'
